using namespace std;

class Solution {
public:
    string frequencySort(string s) {
        int freq[128] = {0};
        for (char c : s) {
            freq[c]++;
        }

        vector<pair<int, char>> vec;
        for (int i = 0; i < 128; ++i) {
            if (freq[i] > 0) {
                vec.push_back(make_pair(freq[i], static_cast<char>(i)));
            }
        }

        sort(vec.begin(), vec.end(), [](const pair<int,char>& a, const pair<int,char>& b) {
            return a.first > b.first;
        });

        string res;
        for (const auto& p : vec) {
            res += string(p.first, p.second);
        }

        return res;
    }
};

